$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$sandbox=Join-Path ([IO.Path]::GetTempPath()) ('ueef-memory-'+[guid]::NewGuid().ToString('N'))
try{New-Item -ItemType Directory -Path $sandbox|Out-Null;$write=Join-Path $root 'scripts\write-project-memory.ps1';$read=Join-Path $root 'scripts\get-project-memory.ps1';$record=(& $write -Kind decision -Title 'Cache policy' -Detail 'Use local cache with explicit invalidation.' -Root $sandbox -Json|Out-String)|ConvertFrom-Json;if($record.automaticPolicyChange -or !$record.expiresAt){throw 'Memory record contract failed.'};$items=(& $read -Root $sandbox -Json|Out-String)|ConvertFrom-Json;if(@($items).Count -ne 1){throw 'Memory retrieval failed.'};$rejected=$false;try{& $write -Kind lesson -Title x -Detail 'api_key=secret' -Root $sandbox|Out-Null}catch{$rejected=$true};if(!$rejected){throw 'Secret-looking memory was accepted.'};Write-Host 'Project memory tests passed'}finally{if(Test-Path $sandbox){Remove-Item $sandbox -Recurse -Force}}
